function modalToggle(e,t){e.style.display=t}const btnOpenModal=document.querySelectorAll("[data-show-modal]"),modalWindow=document.querySelector("[data-modal]");for(let e of btnOpenModal)e.addEventListener("click",()=>{modalToggle(modalWindow,"block")});const crossCloseModal=document.querySelectorAll("[data-close-modal]");for(let e of crossCloseModal)e.addEventListener("click",e=>{modalToggle(e.target.closest("[data-modal]"),"none")});const reviewsSlider=new Swiper(".reviews",{navigation:{prevEl:".reviews__nav-prev",nextEl:".reviews__nav-next"},simulateTouch:!0,touchRatio:1,touchAngle:45,grabCursor:!0,loop:!0,spaceBetween:0,breakpoints:{1440:{spaceBetween:40},768:{spaceBetween:100},430:{spaceBetween:50},375:{spaceBetween:10},360:{spaceBetween:15},344:{spaceBetween:20}},autoplay:{delay:3e3}}),questions=document.querySelectorAll(".question");questions.forEach(e=>{e.addEventListener("click",()=>{const t=e.querySelector(".question__answer"),o=t.classList,n=e.querySelector(".question__cross");let l=`${t.scrollHeight}px`,s=45;console.log(o.contains("question_active")),o.contains("question_active")?(o.remove("question_active"),l=0,s=0):o.add("question_active"),n.style.transform=`rotate(${s}deg)`,t.style.height=l})});const burgerMenu=document.querySelector(".bar"),mobileMenu=document.querySelector(".menu-mobile"),menuExit=document.querySelector(".menu-mobile__cross");burgerMenu.addEventListener("click",()=>{mobileMenu.style.height="100%"}),menuExit.addEventListener("click",()=>{mobileMenu.style.height="0%"});